-- ============================================
-- FILE 2: Seed Employees, Schedules, Vacations (Oracle SQL)
--
-- REVAMP: Replaces former 02_seed_doctors.sql and 03_seed_staff.sql.
-- Doctor (15) + Staff (24) are now a single Employee table, discriminated by
-- employee_type. Doctors keep IDs 1-15; former staff are remapped to 16-39.
--
--   Doctors (employee_id 1-15):
--     - employee_type = 'Doctor'
--     - specialization + license_number populated
--     - role = NULL
--   Non-clinical staff (employee_id 16-39):
--     - employee_type = Nurse / Lab Technician / Receptionist /
--                       Pharmacist / Administrative Assistant
--     - role populated
--     - specialization + license_number = NULL
--
-- Also seeds:
--   - DoctorSchedule (205 rows) -- employee_id references Employee(Doctor).
--     max_appointments has been REMOVED per the revamp (BR4 retired).
--   - DoctorVacation (6 rows) -- employee_id references Employee(Doctor).
--
-- NOTE: identity columns must use GENERATED BY DEFAULT AS IDENTITY to
-- allow explicit ID inserts.
-- After seeding, reset with:
--   ALTER TABLE Employee MODIFY (employee_id GENERATED ALWAYS AS IDENTITY START WITH LIMIT VALUE);
--   ALTER TABLE DoctorSchedule MODIFY (schedule_id GENERATED ALWAYS AS IDENTITY START WITH LIMIT VALUE);
--   ALTER TABLE DoctorVacation MODIFY (vacation_id GENERATED ALWAYS AS IDENTITY START WITH LIMIT VALUE);
-- ============================================

-- ============================================
-- SECTION 1: Insert 15 Doctors (employee_id 1-15)
-- ============================================

-- Cardiology (dept 1)
