-- Oncology (dept 5)
-- General Surgery (dept 6)
-- Emergency Medicine (dept 7)
-- Internal Medicine (dept 8)

BEGIN
    DBMS_OUTPUT.PUT_LINE('Doctors seeded successfully (15 doctors).');
END;
/

-- ============================================
-- SECTION 2: Insert 24 non-clinical staff (employee_id 16-39)
-- Former Staff table rows, remapped +15.
-- ============================================

-- Nurses (former staff 1-8 -> 16-23)

-- Lab Technicians (former staff 9-12 -> 24-27)

-- Receptionists (former staff 13-16 -> 28-31)

-- Pharmacists (former staff 17-20 -> 32-35)

-- Administrative Assistants (former staff 21-24 -> 36-39)

BEGIN
    DBMS_OUTPUT.PUT_LINE('Non-clinical staff seeded successfully (24 employees, IDs 16-39).');
END;
/

-- ============================================
-- SECTION 3: Update Department head_employee_id
-- Each department is headed by its senior doctor.
-- ============================================
UPDATE Department SET head_employee_id = 1  WHERE department_id = 1;  -- Cardiology -> Dr. Chen
UPDATE Department SET head_employee_id = 3  WHERE department_id = 2;  -- Orthopedics -> Dr. Johnson
UPDATE Department SET head_employee_id = 5  WHERE department_id = 3;  -- Neurology -> Dr. Kim
UPDATE Department SET head_employee_id = 7  WHERE department_id = 4;  -- Pediatrics -> Dr. O'Brien
UPDATE Department SET head_employee_id = 9  WHERE department_id = 5;  -- Oncology -> Dr. Nguyen
UPDATE Department SET head_employee_id = 11 WHERE department_id = 6;  -- General Surgery -> Dr. Wright
UPDATE Department SET head_employee_id = 12 WHERE department_id = 7;  -- Emergency Medicine -> Dr. Lee
UPDATE Department SET head_employee_id = 14 WHERE department_id = 8;  -- Internal Medicine -> Dr. Davis

BEGIN
    DBMS_OUTPUT.PUT_LINE('Department head employees assigned successfully.');
END;
/

